// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.config;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.eclipse.rdf4j.model.Model;
import org.eclipse.rdf4j.model.impl.LinkedHashModel;
import org.junit.jupiter.api.Test;

class LmdbStoreConfigMemoryBudgetTest {

	@Test
	void memoryBudgetDefaultsTo256MiBAndRoundTrips() {
		LmdbStoreConfig config = new LmdbStoreConfig();
		assertEquals(256L * 1024L * 1024L, config.getSketchEstimatorMemoryBudgetBytes());

		config.setSketchEstimatorMemoryBudgetBytes(64L * 1024L * 1024L);
		Model model = new LinkedHashModel();
		var node = config.export(model);
		assertTrue(model.contains(node, LmdbStoreSchema.SKETCH_ESTIMATOR_MEMORY_BUDGET_BYTES, null));

		LmdbStoreConfig parsed = new LmdbStoreConfig();
		parsed.parse(model, node);
		assertEquals(64L * 1024L * 1024L, parsed.getSketchEstimatorMemoryBudgetBytes());
	}

	@Test
	void memoryBudgetRejectsValuesBelowOneMiB() {
		LmdbStoreConfig config = new LmdbStoreConfig();
		assertThrows(IllegalArgumentException.class, () -> config.setSketchEstimatorMemoryBudgetBytes(1024L));
	}
}
